use Storable qw(nstore retrieve);

# Function to save a session
sub save_session {
    my ($session) = @_;
    nstore($session, "/tmp/sess_$session->{'id'});
}

# Function to load a session
sub load_session {
    my ($session_id) = @_;
    my $session = retrieve("/tmp/sess_$session_id");
    return $session;
}

# Function to accept session IDs from cookies and load sessions
sub accept_session {
